    @Test
    public void heyJude() {
        List<String> segments = MorseCodeDecoder.getSegments("0000000011011010011100000110000001111110100111110011111100000000000111011111111011111011111000000101100011111100000111110011101100000100000");
        int[] dotAndDash = MorseCodeDecoder.getDotAndDashLengths(segments);
        assertEquals(dotAndDash[0], 3);
        assertEquals(dotAndDash[1], 8);
        String morse = MorseCodeDecoder.segmentsToMorse(dotAndDash, segments);
        assertEquals("HEY JUDE", MorseCodeDecoder.decodeMorse(morse));
    }

    @Test
    public void brownFox1() {
        List<String> segments = MorseCodeDecoder.getSegments("");
        int[] dotAndDash = MorseCodeDecoder.getDotAndDashLengths(segments);
        assertEquals(4, dotAndDash[0]);
        assertEquals(10, dotAndDash[1]);
        String morse = MorseCodeDecoder.segmentsToMorse(dotAndDash, segments);
        assertEquals("THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG", MorseCodeDecoder.decodeMorse(morse));
    }
    @Test
    public void brownFox2() {
        List<String> segments = MorseCodeDecoder.getSegments("");
        int[] dotAndDash = MorseCodeDecoder.getDotAndDashLengths(segments);
        assertEquals(7, dotAndDash[0]);
        assertEquals(dotAndDash[1], 17);
        String morse = MorseCodeDecoder.segmentsToMorse(new int[]{7,17}, segments);
        assertEquals("SOS! THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG.", MorseCodeDecoder.decodeMorse(morse));
    }

